/* ========== SECTION PILL ========== */
.section-pill {
  display: inline-flex;
  align-items: center;
  gap: 0.45rem;
  padding: 0.28rem 0.9rem;
  border-radius: 100px;
  border: 1px solid var(--border-color);
  color: var(--text-muted);
  font-size: 0.775rem;
  font-weight: 600;
  letter-spacing: 0.01em;
  margin-bottom: 1rem;
}

.section-pill::before {
  content: '';
  display: inline-block;
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--color-primary);
  flex-shrink: 0;
}

/* ========== HERO SHOWCASE CARDS ========== */
.landing__hero-showcase {
  width: 100%;
  padding: 3rem 0 1rem;
  z-index: 1;
  position: relative;
}

.landing__showcase-cards {
  display: grid;
  grid-template-columns: 1fr 1.15fr 1fr;
  gap: 1.25rem;
  align-items: start;
}

.landing__showcase-card {
  background: var(--bg-surface);
  border: 1px solid var(--border-color);
  border-radius: 16px;
  padding: 1.4rem;
  display: flex;
  flex-direction: column;
  gap: 1rem;
  transition: border-color 0.2s ease;
}

.landing__showcase-card:hover {
  border-color: var(--border-hover);
}

.landing__showcase-card--featured {
  background: rgba(99,102,241,0.05);
  border-color: rgba(99,102,241,0.28);
  box-shadow: 0 0 40px rgba(99,102,241,0.08);
}

.landing__showcase-card-header {
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.landing__showcase-card-icon {
  font-size: 1.3rem;
  width: 40px;
  height: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--bg-surface-2);
  border: 1px solid var(--border-color);
  border-radius: 10px;
  flex-shrink: 0;
}

.landing__showcase-card-title {
  font-size: 0.9rem;
  font-weight: 700;
  color: var(--text-primary);
  line-height: 1.2;
}

.landing__showcase-card-sub {
  font-size: 0.75rem;
  color: var(--text-muted);
  margin-top: 0.1rem;
}

.landing__showcase-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 0.4rem;
}

.landing__showcase-tag {
  font-size: 0.7rem;
  padding: 0.2rem 0.55rem;
  background: var(--bg-surface-2);
  border: 1px solid var(--border-color);
  border-radius: 100px;
  color: var(--text-muted);
}

.landing__showcase-output {
  display: flex;
  flex-direction: column;
  gap: 0.45rem;
}

.landing__showcase-line {
  height: 8px;
  background: linear-gradient(90deg, rgba(99,102,241,0.55), rgba(139,92,246,0.35));
  border-radius: 4px;
  transform-origin: left center;
}

.landing__showcase-badge {
  font-size: 0.72rem;
  color: var(--color-primary-light);
  background: rgba(99,102,241,0.1);
  border: 1px solid rgba(99,102,241,0.2);
  border-radius: 100px;
  padding: 0.25rem 0.75rem;
  display: inline-block;
  width: fit-content;
}

.landing__showcase-metrics {
  display: flex;
  gap: 2rem;
}

.landing__showcase-metric-val {
  display: block;
  font-size: 1.8rem;
  font-weight: 900;
  letter-spacing: -0.04em;
  color: var(--text-primary);
  line-height: 1;
}

.landing__showcase-metric-label {
  font-size: 0.72rem;
  color: var(--text-muted);
  margin-top: 0.2rem;
}

/* ========== HOW IT WORKS (BOTDESK LAYOUT) ========== */
.landing__how-layout {
  display: grid;
  grid-template-columns: 1fr 1.5fr;
  gap: 4rem;
  align-items: start;
  margin-top: 3rem;
}

.landing__how-steps-col {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}

.landing__how-step-row {
  display: flex;
  gap: 1.1rem;
  align-items: flex-start;
  padding: 1.1rem 1.25rem;
  border-radius: 12px;
  background: transparent;
  border: 1px solid transparent;
  cursor: pointer;
  text-align: left;
  width: 100%;
  transition: background 0.18s ease, border-color 0.18s ease;
}

.landing__how-step-row:hover {
  background: var(--bg-surface-2);
}

.landing__how-step-row.active {
  background: var(--bg-surface);
  border-color: var(--border-color);
}

.landing__how-step-row-num {
  width: 34px;
  height: 34px;
  border-radius: 50%;
  background: var(--bg-surface-2);
  border: 1px solid var(--border-color);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.78rem;
  font-weight: 800;
  color: var(--text-muted);
  flex-shrink: 0;
  transition: background 0.18s ease, color 0.18s ease, border-color 0.18s ease;
}

.landing__how-step-row.active .landing__how-step-row-num {
  background: var(--color-primary);
  border-color: var(--color-primary);
  color: white;
}

.landing__how-step-row-content {
  flex: 1;
  padding-top: 0.35rem;
}

.landing__how-step-row-title {
  font-size: 1rem;
  font-weight: 700;
  color: var(--text-primary);
  line-height: 1.3;
}

.landing__how-step-row-desc {
  font-size: 0.875rem;
  color: var(--text-muted);
  line-height: 1.65;
  margin-top: 0.5rem;
  overflow: hidden;
}

.landing__how-visual-col {
  position: sticky;
  top: 6rem;
}

/* ========== RESPONSIVE ADDITIONS ========== */
@media (max-width: 900px) {
  .landing__showcase-cards {
    grid-template-columns: 1fr;
    max-width: 420px;
    margin: 0 auto;
  }

  .landing__how-layout {
    grid-template-columns: 1fr;
    gap: 2rem;
  }

  .landing__how-visual-col {
    position: static;
  }
}
```

